alter table companies  add column if not exists info     jsonb default '{}'::jsonb;
alter table companies  add column if not exists contacts jsonb default '[]'::jsonb;
alter table candidates add column if not exists pipeline jsonb default '{}'::jsonb;
alter table candidates add column if not exists batch    text;

delete from app_users where company_id in ('c1','c2','c3') or candidate_id in ('p1','p2','p3','p4','p5');
delete from candidates where id in ('p1','p2','p3','p4','p5');
delete from companies  where id in ('c1','c2','c3');

